/**
 * User object constructed after reading data from backend DB
 * @typedef {import('@providers/User').ProfileData} ProfileData
 */

/**
 * Success response object received from 'kaagzi-lambda-cashFreePg-createOrder' lambda function
 * @typedef {Object} CreateOrderSuccessResponse
 * @property {!1} s - Response status
 * @property {!string} oid - Order ID
 * @property {!string} psid - Order Payment Session ID
 * @property {!string} t - Order creation date as ISO-string eg "2023-03-18T23:07:16.112Z"
 * @property {!string} x - Order expiry date as ISO-string eg "2023-03-18T23:07:16.112Z"
 */

/**
 * Error response object received from 'kaagzi-lambda-cashFreePg-createOrder' lambda function
 * @typedef {Object} CreateOrderErrorResponse
 * @property {!0} s - Response status
 * @property {!string} m - Error Message. Present in case above property s === 0
 */

/**
 * Order (whose payment is underway) stored in localstorage.
 * @typedef {Object} StoredWipOrderData
 * @property {!string} u - User ID
 * @property {!string} oid - Order ID
 * @property {!string} psid - Order Payment Session ID
 * @property {!string} t - Order creation datetime as ISO string
 * @property {!string} x - Order expiry datetime as ISO string
 */

