/**
 * React context for Payment Gateway
 */
export const PaymentGatewayContext = createContext({
	// /**
	//  * Creates a new payment order with the payment gateway and takes user to payment page hosted by payment gateway
	//  * @param {!1|2|3} plan - Payment Plan
	//  * @param {?Number} [interimPhone] - Phone number (If phone from user profile data saved in backend is not available)
	//  * @returns {Promise<?CreateOrderSuccessResponse>} Object containing the Order-ID and the Payment-Session-ID
	//  * @see {@link CreateOrderSuccessResponse}
	//  */
	// createOrder_n_navigateToPaymentPage: async (plan, interimPhone) => {}, // eslint-disable-line no-unused-vars

	// /**
	//  * Creates a new payment order with the payment gateway and displays a popup modal
	//  * @param {!1|2|3} plan - Payment Plan
	//  * @param {?Number} [interimPhone] - Phone number (If phone from user profile data saved in backend is not available)
	//  * @returns {Promise<?('active'|'paid'|'unknown')>} order status or null in case of failure
	//  */
	// createOrder_n_showPopup: async (plan, interimPhone) => {}, // eslint-disable-line no-unused-vars

	/**
	 * Creates a new payment order with the payment gateway and initiates payment.
	 * Note that even in case of popup, if the user chooses bank-transfer, he/she shall be redirected to PG pay page from the modal.
	 * Thus it is imp to store the details of the order being paid in localstorage so as to be able to check for it once we are redirected back.
	 * @param {!1|2|3} plan - Payment Plan
	 * @param {?Number} [interimPhone] - Phone number (In case phone from user profile data saved in backend is not available)
	 * @param {?Boolean} [redirect=false] - If FALSE, Shows payment form inside a modal | If TRUE, redirects to PG page
	 * @returns {Promise<?('active'|'paid'|'unknown'|Boolean)>} order status or null in case of failure
	 */
	initPayment: async (plan, interimPhone, redirect) => {}, // eslint-disable-line no-unused-vars

	/*/**
	 * Checks status of payment-order
	 * @param {!number} orderId - Order ID
	 * @returns {Promise<?('active'|'paid'|'unknown')>} order status or null in case of failure
	 */
	//__checkOrderStatus: async (orderId) => {}, // eslint-disable-line no-unused-vars,
});

